content.content:
// Modal centrado al 90% de ancho
ogComponent('modal').open('ejemplos|sections/formularios/main', {
  title: 'Galería de Formularios',
  width: '90%',
  maxWidth: '1400px'
});

// O como panel lateral
ogComponent('modal').open('ejemplos|sections/formularios/main', {
  title: 'Formularios',
  panel: 'right',
  panelSize: 'w90'
});

ogComponent('modal').open('ejemplos|sections/caracteristicas-json-parts', {
  title: 'JSON Parts — División de Vistas',
  width: '80%',
  maxWidth: '1100px'
});

// Vista de una extensión
ogComponent('modal').open('miext|sections/mi-vista', { title: '...' });

// Formulario de una extensión
ogComponent('modal').open('miext|forms/mi-form', { title: '...' });

// Vista del framework o middle
ogComponent('modal').open('middle:sections/mi-vista', { title: '...' });

// Formulario del framework
ogComponent('modal').open('core:forms/mi-form', { title: '...' });

// HTML directo (sin carga)
ogComponent('modal').open('<p>Contenido inline</p>', { html: true, title: '...' });
